import { createContext, useContext, useState, useEffect } from 'react';

const ThemeContext = createContext();

export function ThemeProvider({ children }) {
    const [theme, setTheme] = useState(() => {
        return localStorage.getItem('visa-theme') || 'light';
    });

    useEffect(() => {
        document.documentElement.setAttribute('data-theme', theme);
        localStorage.setItem('visa-theme', theme);
    }, [theme]);

    const toggleTheme = () => {
        setTheme(prev => prev === 'light' ? 'blue-gold' : 'light');
    };

    return (
        <ThemeContext.Provider value={{ theme, toggleTheme }}>
            {children}
        </ThemeContext.Provider>
    );
}

export function useTheme() {
    const context = useContext(ThemeContext);
    if (!context) throw new Error('useTheme must be used within ThemeProvider');
    return context;
}

import { useEffect, useState } from 'react';
import { motion } from 'framer-motion';

export default function CustomCursor() {
    const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
    const [isHovering, setIsHovering] = useState(false);

    useEffect(() => {
        const updateMousePosition = (e) => {
            setMousePosition({ x: e.clientX, y: e.clientY });
        };

        const handleMouseOver = (e) => {
            if (e.target.tagName.toLowerCase() === 'a' || e.target.tagName.toLowerCase() === 'button' || e.target.closest('button') || e.target.closest('a')) {
                setIsHovering(true);
            } else {
                setIsHovering(false);
            }
        };

        window.addEventListener('mousemove', updateMousePosition);
        window.addEventListener('mouseover', handleMouseOver);

        return () => {
            window.removeEventListener('mousemove', updateMousePosition);
            window.removeEventListener('mouseover', handleMouseOver);
        };
    }, []);

    // Also hiding default cursor in global css might be needed but for now this adds the dot
    return (
        <>
            <motion.div
                className="fixed top-0 left-0 w-4 h-4 rounded-full bg-gold pointer-events-none z-[9999] mix-blend-difference hidden md:block"
                animate={{
                    x: mousePosition.x - 8,
                    y: mousePosition.y - 8,
                    scale: isHovering ? 1.5 : 1
                }}
                transition={{ type: 'spring', mass: 0.1, stiffness: 800, damping: 50 }}
            />
            <motion.div
                className="fixed top-0 left-0 w-10 h-10 rounded-full border border-gold/50 pointer-events-none z-[9998] hidden md:block"
                animate={{
                    x: mousePosition.x - 20,
                    y: mousePosition.y - 20,
                    scale: isHovering ? 1.2 : 1
                }}
                transition={{ type: 'spring', mass: 0.2, stiffness: 300, damping: 30 }}
            />
        </>
    );
}

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Menu, X, Globe, Sun, Moon } from 'lucide-react';
import { useTheme } from '../ThemeContext';

import { Link as RouterLink, useLocation, useNavigate } from 'react-router-dom';

const navLinks = [
    { name: 'Home', href: '/#home' },
    { name: 'About', href: '/#about' },
    { name: 'Visa Types', href: '/#visa-categories' },
    { name: 'Destinations', href: '/#countries' },
    { name: 'Testimonials', href: '/#testimonials' },
    { name: 'Contact', href: '/#contact' },
];

export default function Navbar() {
    const [scrolled, setScrolled] = useState(false);
    const [isOpen, setIsOpen] = useState(false);
    const { theme, toggleTheme } = useTheme();

    useEffect(() => {
        const handleScroll = () => setScrolled(window.scrollY > 50);
        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    const isLight = theme === 'light';
    const location = useLocation();
    const navigate = useNavigate();

    // Scroll to section when route changes to a hash
    useEffect(() => {
        if (location.hash) {
            const id = location.hash.replace('#', '');
            const element = document.getElementById(id);
            if (element) {
                // Wait briefly for rendering
                setTimeout(() => {
                    element.scrollIntoView({ behavior: 'smooth' });
                }, 100);
            }
        }
    }, [location]);

    const handleNavClick = (e, href) => {
        e.preventDefault();
        setIsOpen(false);
        // If it's a hash link to the current path, just scroll
        if (href.startsWith('/#') && location.pathname === '/') {
            const id = href.replace('/#', '');
            const element = document.getElementById(id);
            if (element) {
                element.scrollIntoView({ behavior: 'smooth' });
            } else {
                navigate(href);
            }
        } else {
            navigate(href);
        }
    };
    return (
        <motion.nav
            initial={{ y: -100 }}
            animate={{ y: 0 }}
            transition={{ duration: 0.6, ease: 'easeOut' }}
            // On large screens, Topbar takes up ~36px (py-2 is 8px top/bottom + text).
            // We'll push the Navbar down by that much when at the top, but lock to top when scrolled.
            className={`fixed left-0 right-0 z-50 transition-all duration-500 ${scrolled ? 'top-0 py-2 lg:top-0' : 'top-0 py-4 lg:top-[36px]'}`}
            style={{
                backgroundColor: scrolled
                    ? (isLight ? 'rgba(243, 241, 236, 0.95)' : 'rgba(10,17,40,0.95)')
                    : 'transparent',
                backdropFilter: scrolled ? 'blur(16px)' : 'none',
                boxShadow: scrolled
                    ? (isLight ? '0 4px 20px rgba(0,0,0,0.05)' : '0 4px 20px rgba(0,0,0,0.2)')
                    : 'none',
                borderBottom: scrolled
                    ? (isLight ? '1px solid rgba(26,35,126,0.05)' : '1px solid rgba(255,255,255,0.05)')
                    : '1px solid transparent',
            }}
        >
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                <div className="flex items-center justify-between h-16">
                    {/* Logo */}
                    <RouterLink to="/" className="flex items-center gap-3 group">
                        <div className="relative">
                            <img src="/logo.png" alt="Caspianorthoverseas Logo" className="w-16 h-16 object-contain transform group-hover:scale-110 transition-transform duration-300 drop-shadow-md" />
                            <div className="absolute inset-0 rounded-xl gradient-gold opacity-0 group-hover:opacity-50 blur-lg transition-opacity duration-300" />
                        </div>
                        <div>
                            <span className="text-xl font-bold font-heading tracking-tight">
                                <span className={`transition-colors duration-300 ${isLight ? 'text-navy' : 'text-white'}`}>CaspiaNorth</span>
                                <span className="text-gradient-gold">Overseas</span>
                            </span>
                        </div>
                    </RouterLink>

                    {/* Desktop Nav */}
                    <div className="hidden lg:flex items-center gap-1">
                        {navLinks.map((link) => (
                            <a
                                key={link.name}
                                href={link.href}
                                onClick={(e) => handleNavClick(e, link.href)}
                                className={`px-4 py-2 text-sm font-medium transition-colors duration-300 rounded-lg ${isLight
                                    ? 'text-navy/80 hover:text-gold hover:bg-royal-blue/5'
                                    : 'text-white/80 hover:text-gold hover:bg-white/10'
                                    }`}
                            >
                                {link.name}
                            </a>
                        ))}
                    </div>

                    {/* Right side: Theme Toggle + CTA */}
                    <div className="hidden lg:flex items-center gap-3">
                        <button
                            onClick={toggleTheme}
                            className={`p-2 rounded-full transition-colors duration-300 ${isLight
                                ? 'text-navy hover:text-gold hover:bg-royal-blue/5'
                                : 'text-white hover:text-gold hover:bg-white/10'
                                }`}
                            aria-label="Toggle Theme"
                        >
                            {isLight ? <Moon className="w-5 h-5" /> : <Sun className="w-5 h-5" />}
                        </button>
                        <a
                            href="/#contact"
                            onClick={(e) => handleNavClick(e, '/#contact')}
                            className="relative px-6 py-2.5 text-sm font-semibold text-navy rounded-full gradient-gold hover:shadow-lg hover:shadow-gold/30 transition-all duration-300 transform hover:scale-105 active:scale-95 shadow-md"
                        >
                            Free Consultation
                        </a>
                    </div>

                    {/* Mobile: Theme Toggle + Menu Toggle */}
                    <div className="lg:hidden flex items-center gap-2">
                        <button
                            onClick={toggleTheme}
                            className={`p-2 rounded-full transition-colors duration-300 ${isLight
                                ? 'text-navy hover:text-gold hover:bg-royal-blue/5'
                                : 'text-white hover:text-gold hover:bg-white/10'
                                }`}
                            aria-label="Toggle Theme"
                        >
                            {isLight ? <Moon className="w-5 h-5" /> : <Sun className="w-5 h-5" />}
                        </button>
                        <button
                            onClick={() => setIsOpen(!isOpen)}
                            className={`p-2 rounded-lg transition-colors ${isLight
                                ? 'text-navy hover:text-gold hover:bg-royal-blue/5'
                                : 'text-white hover:text-gold hover:bg-white/10'
                                }`}
                        >
                            {isOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6 bg-transparent rounded-md p-0.5 shadow-sm" />}
                        </button>
                    </div>
                </div>
            </div>

            {/* Mobile Menu */}
            <AnimatePresence>
                {isOpen && (
                    <motion.div
                        initial={{ opacity: 0, height: 0 }}
                        animate={{ opacity: 1, height: 'auto' }}
                        exit={{ opacity: 0, height: 0 }}
                        transition={{ duration: 0.3 }}
                        style={{
                            backgroundColor: isLight ? 'rgba(255,255,255,0.98)' : 'rgba(10,17,40,0.98)',
                            borderTop: isLight ? '1px solid rgba(26,35,126,0.05)' : '1px solid rgba(255,255,255,0.05)',
                        }}
                        className="lg:hidden backdrop-blur-xl absolute top-full left-0 right-0 overflow-hidden shadow-2xl origin-top pointer-events-auto z-[60]"
                    >
                        <div className="px-4 py-6 space-y-1">
                            {navLinks.map((link, i) => (
                                <motion.a
                                    key={link.name}
                                    href={link.href}
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: i * 0.05 }}
                                    onClick={(e) => handleNavClick(e, link.href)}
                                    className={`block px-4 py-3 text-base font-medium rounded-lg transition-colors ${isLight
                                        ? 'text-navy hover:text-gold hover:bg-royal-blue/5'
                                        : 'text-white hover:text-gold hover:bg-white/10'
                                        }`}
                                >
                                    {link.name}
                                </motion.a>
                            ))}
                            <div className="pt-4">
                                <a
                                    href="/#contact"
                                    onClick={(e) => handleNavClick(e, '/#contact')}
                                    className="block text-center px-6 py-3 text-sm font-semibold text-navy rounded-full gradient-gold"
                                >
                                    Free Consultation
                                </a>
                            </div>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </motion.nav>
    );
}

import { useState, useEffect } from 'react';
import { motion, useInView, AnimatePresence } from 'framer-motion';
import { useRef } from 'react';
import { Target, Eye, Users } from 'lucide-react';
import useIsMobile from '../../hooks/useIsMobile';
import aboutUsImg from '../../assets/aboutus.png'; // Reverting to the new user provided image
import { CheckCircle2 } from 'lucide-react';

const values = [
    { icon: Target, title: 'Our Mission', desc: 'To simplify visa processing and make international travel accessible for everyone, regardless of complexity.' },
    { icon: Eye, title: 'Our Vision', desc: 'To be the most trusted visa consultancy brand globally, known for transparency and exceptional success rates.' },
    { icon: Users, title: 'Expert Team', desc: '50+ certified immigration consultants with decades of combined experience across all major embassies.' },
];

export default function AboutUs() {
    const ref = useRef(null);
    const isInView = useInView(ref, { once: true, margin: '-80px' });
    const isMobile = useIsMobile();
    const show = isMobile || isInView;

    return (
        <section id="about" className="relative py-24 md:py-32 overflow-hidden" style={{ background: 'var(--t-bg-section)', transition: 'background 0.4s ease' }}>
            <div className="absolute right-0 top-1/2 -translate-y-1/2 w-[500px] h-[500px] bg-[var(--t-blob-1)] rounded-full blur-[150px] pointer-events-none" />
            <div className="absolute left-0 top-20 w-[400px] h-[400px] bg-[var(--t-blob-2)] rounded-full blur-[120px] pointer-events-none" />

            <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8" ref={ref}>
                <div className="flex flex-col lg:flex-row gap-12 lg:gap-20 items-center mb-16 lg:mb-24">

                    {/* Left — Huge Image Feature */}
                    <motion.div
                        initial={isMobile ? false : { opacity: 0, x: -40 }}
                        animate={show ? { opacity: 1, x: 0 } : {}}
                        transition={{ duration: 0.8, ease: 'easeOut' }}
                        className="w-full lg:w-1/2 relative"
                    >
                        {/* Decorative background border */}
                        <div className="absolute -inset-4 bg-gradient-to-tr from-gold/20 to-transparent rounded-[2.5rem] blur-xl opacity-50" />

                        <div className="relative w-full aspect-[4/5] sm:aspect-square lg:aspect-[4/5] rounded-[2rem] overflow-hidden shadow-2xl border border-white/10 group">
                            <img
                                src={aboutUsImg}
                                alt="Caspianorthoverseas consulting team"
                                className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-[1.5s] ease-out"
                            />
                            {/* Inner gradient for text legibility */}
                            <div className="absolute inset-0 bg-gradient-to-t from-navy/90 via-navy/20 to-transparent" />

                            {/* Floating Stats over Image */}
                            <div className="absolute bottom-6 left-6 right-6 grid grid-cols-3 gap-3">
                                {[
                                    { val: '12+', label: 'Years' },
                                    { val: '50K+', label: 'Visas' },
                                    { val: '99%', label: 'Success' },
                                ].map((s, i) => (
                                    <motion.div
                                        key={i}
                                        initial={isMobile ? false : { opacity: 0, y: 20 }}
                                        animate={show ? { opacity: 1, y: 0 } : {}}
                                        transition={{ delay: 0.5 + i * 0.1 }}
                                        className="bg-white/10 backdrop-blur-md rounded-xl p-3 sm:p-4 text-center border border-white/20"
                                    >
                                        <div className="text-xl sm:text-2xl font-heading font-bold text-white drop-shadow-md">{s.val}</div>
                                        <div className="text-[10px] sm:text-xs text-gold uppercase tracking-widest mt-1 font-bold">{s.label}</div>
                                    </motion.div>
                                ))}
                            </div>
                        </div>
                    </motion.div>

                    {/* Right — Content area & Slideshow */}
                    <motion.div
                        initial={isMobile ? false : { opacity: 0, x: 40 }}
                        animate={show ? { opacity: 1, x: 0 } : {}}
                        transition={{ duration: 0.8, ease: 'easeOut' }}
                        className="w-full lg:w-1/2"
                    >
                        <span className="inline-block px-4 py-1.5 rounded-full gradient-gold text-navy font-bold text-sm tracking-wider uppercase border border-gold/20 mb-6 drop-shadow-sm">
                            About Caspianorthoverseas
                        </span>

                        <h2 className="text-3xl sm:text-4xl lg:text-5xl font-heading font-bold mb-6 leading-[1.2]">
                            <span className="t-text">We Make Visas </span>
                            <span className="text-gradient-gold">Simple</span>
                        </h2>

                        <p className="t-text-muted text-base sm:text-lg leading-relaxed mb-6">
                            Founded in 2014, Caspianorthoverseas has grown from a small consultancy office to one of the region's most trusted visa and immigration companies. We've helped over 50,000 clients from 60+ nationalities navigate the complex world of international travel and relocation.
                        </p>

                        <p className="t-text-sec text-base leading-relaxed mb-8">
                            Whether you are pursuing higher education, seeking lucrative career opportunities aboard, planning a dream vacation, or reuniting with family, our bespoke services are tailored to your unique journey. We handle the paperwork, so you can focus on the destination.
                        </p>

                        {/* Feature List for better UI */}
                        <div className="space-y-4 mb-10">
                            {[
                                'End-to-end documentation support',
                                'Expert interview preparation',
                                'Direct embassy liaison services',
                                'Transparent step-by-step guidance'
                            ].map((item, idx) => (
                                <div key={idx} className="flex items-center gap-3">
                                    <CheckCircle2 className="w-5 h-5 text-gold shrink-0" />
                                    <span className="t-text font-medium text-sm md:text-base">{item}</span>
                                </div>
                            ))}
                        </div>

                        <div className="flex flex-wrap gap-4 mt-8">
                            <a
                                href="#contact"
                                onClick={(e) => {
                                    e.preventDefault();
                                    document.getElementById('contact')?.scrollIntoView({ behavior: 'smooth' });
                                }}
                                className="px-8 py-3.5 rounded-full gradient-gold text-navy font-bold shadow-lg shadow-gold/20 hover:shadow-gold/40 hover:-translate-y-0.5 transition-all duration-300 text-center"
                            >
                                Start Your Journey
                            </a>
                        </div>
                    </motion.div>
                </div>

                {/* Values List Moved to Bottom */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8 pt-10 border-t border-white/5 lg:pt-16" style={{ borderColor: 'var(--t-surface-border)' }}>
                    {values.map((v, i) => (
                        <motion.div
                            key={i}
                            initial={isMobile ? false : { opacity: 0, y: 30 }}
                            animate={show ? { opacity: 1, y: 0 } : {}}
                            transition={{ duration: 0.5, delay: 0.2 + i * 0.15 }}
                            className="glass-card p-8 rounded-2xl flex flex-col items-center text-center group hover:-translate-y-2 transition-transform duration-300"
                        >
                            <div className="w-16 h-16 rounded-2xl bg-gold/10 flex items-center justify-center mb-6 group-hover:bg-gold transition-colors duration-300 shadow-sm border border-gold/20">
                                <v.icon className="w-8 h-8 text-gold group-hover:text-navy transition-colors duration-300" />
                            </div>
                            <h3 className="text-xl font-heading font-bold t-text mb-3 group-hover:text-gold transition-colors">{v.title}</h3>
                            <p className="text-sm t-text-muted leading-relaxed">{v.desc}</p>
                        </motion.div>
                    ))}
                </div>
            </div>
        </section>
    );
}

import { useEffect, useState, useRef } from 'react';
import { motion, useInView } from 'framer-motion';
import { Trophy, Users, Star, Clock, CheckCircle, TrendingUp } from 'lucide-react';
import useIsMobile from '../../hooks/useIsMobile';

const containerVariants = { hidden: {}, visible: { transition: { staggerChildren: 0.1 } } };
const cardVariants = {
    hidden: { opacity: 0, y: 30 },
    visible: { opacity: 1, y: 0, transition: { duration: 0.5 } },
};

const achievements = [
    {
        icon: CheckCircle,
        value: 5000,
        suffix: '+',
        label: 'Visas Approved',
        description: 'Successfully processed across all categories',
        color: 'text-gold',
        bg: 'from-gold/15 to-gold/5',
        border: 'hover:border-gold/40',
    },
    {
        icon: TrendingUp,
        value: 99,
        suffix: '%',
        label: 'Success Rate',
        description: 'First-attempt visa approval rate',
        color: 'text-emerald-400',
        bg: 'from-emerald-500/15 to-emerald-500/5',
        border: 'hover:border-emerald-400/40',
    },
    {
        icon: Users,
        value: 3500,
        suffix: '+',
        label: 'Happy Clients',
        description: 'Families and individuals served globally',
        color: 'text-blue-400',
        bg: 'from-blue-500/15 to-blue-500/5',
        border: 'hover:border-blue-400/40',
    },
    {
        icon: Clock,
        value: 10,
        suffix: '+',
        label: 'Years of Experience',
        description: 'Expert visa consultancy you can trust',
        color: 'text-pink-400',
        bg: 'from-pink-500/15 to-pink-500/5',
        border: 'hover:border-pink-400/40',
    },
    {
        icon: Star,
        value: 4.9,
        suffix: '/5',
        label: 'Client Rating',
        description: 'Average rating from verified reviews',
        color: 'text-gold',
        bg: 'from-gold/15 to-amber-600/5',
        border: 'hover:border-gold/40',
        isDecimal: true,
    },
    {
        icon: Trophy,
        value: 4,
        suffix: '',
        label: 'Countries Served',
        description: 'Canada, USA, Gulf Countries & Australia',
        color: 'text-purple-400',
        bg: 'from-purple-500/15 to-purple-500/5',
        border: 'hover:border-purple-400/40',
    },
];

function AnimatedCounter({ target, suffix, isDecimal, isInView }) {
    const [count, setCount] = useState(0);

    useEffect(() => {
        if (!isInView) return;
        const duration = 2000;
        const steps = 60;
        const increment = target / steps;
        let current = 0;
        let step = 0;

        const timer = setInterval(() => {
            step++;
            current = Math.min(current + increment, target);
            setCount(isDecimal ? parseFloat(current.toFixed(1)) : Math.floor(current));
            if (step >= steps) {
                clearInterval(timer);
                setCount(target);
            }
        }, duration / steps);

        return () => clearInterval(timer);
    }, [isInView, target, isDecimal]);

    return (
        <span>
            {isDecimal ? count.toFixed(1) : count.toLocaleString()}{suffix}
        </span>
    );
}

const slideImages = [
    'https://images.unsplash.com/photo-1436450412740-6b988f486c6b?auto=format&fit=crop&w=800&q=80', // travel/airplane
    'https://images.unsplash.com/photo-1522202176988-66273c2fd55f?auto=format&fit=crop&w=800&q=80', // success team Group
    'https://images.unsplash.com/photo-1569098644584-210bcd375b59?auto=format&fit=crop&w=800&q=80', // university grad
    'https://images.unsplash.com/photo-1565684728564-eff5e5a95cb8?auto=format&fit=crop&w=800&q=80'  // global map
];

export default function Achievements() {
    const ref = useRef(null);
    const isInView = useInView(ref, { once: true, margin: '-100px' });
    const isMobile = useIsMobile();
    const show = isMobile || isInView;


    return (
        <section id="achievements" className="relative py-24 md:py-32 overflow-hidden" style={{ background: 'var(--t-bg)', transition: 'background 0.4s ease' }}>
            <div className="absolute top-0 left-1/4 w-[500px] h-[500px] bg-[var(--t-blob-1)] rounded-full blur-[150px] pointer-events-none" />
            <div className="absolute bottom-0 right-1/4 w-[500px] h-[500px] bg-[var(--t-blob-2)] rounded-full blur-[150px] pointer-events-none" />

            <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8" ref={ref}>
                <motion.div initial={isMobile ? false : { opacity: 0, y: 30 }} animate={show ? { opacity: 1, y: 0 } : {}} transition={{ duration: 0.6 }} className="text-center mb-16">
                    <span className="inline-block px-4 py-1.5 rounded-full gradient-gold text-navy font-bold text-sm tracking-wider uppercase mb-4">
                        <Trophy className="w-3.5 h-3.5 inline mr-1.5" />
                        Our Achievements
                    </span>
                    <h2 className="text-3xl md:text-5xl font-heading font-bold mb-4">
                        <span className="t-text">Numbers That </span>
                        <span className="text-gradient-gold">Speak</span>
                    </h2>
                    <p className="t-text-muted max-w-xl mx-auto text-lg">
                        Years of expertise, thousands of success stories, and a commitment to excellence
                    </p>
                </motion.div>

                <div className="flex flex-col lg:flex-row gap-12 items-center">
                    {/* Image Section with Slideshow */}
                    <motion.div
                        initial={isMobile ? false : { opacity: 0, x: -30 }}
                        animate={show ? { opacity: 1, x: 0 } : {}}
                        transition={{ duration: 0.6 }}
                        className="w-full lg:w-5/12 relative"
                    >
                        <div className="relative rounded-3xl overflow-hidden aspect-[4/5] sm:aspect-video lg:aspect-[4/5] shadow-2xl">
                            <motion.img
                                src={slideImages[0]}
                                initial={{ opacity: 0, scale: 1.05 }}
                                animate={{ opacity: 1, scale: 1 }}
