import { useState, useEffect, useRef } from 'react';
import { motion, useInView } from 'framer-motion';
import { Star, ChevronLeft, ChevronRight, Quote } from 'lucide-react';
import useIsMobile from '../../hooks/useIsMobile';

const testimonials = [
    { name: 'Ahmed Khan', visa: 'US Business Visa', rating: 5, text: 'Caspianorthoverseas made my US business visa process incredibly smooth. Got approved in just 2 weeks! The team was professional and kept me updated at every step.', location: 'Dubai, UAE', image: '/testimonials/ahmed_profile_1772208902641.png', visaPhoto: '/testimonials/ahmed_us_visa_1772207950381.png' },
    { name: 'Priya Sharma', visa: 'Canada PR', rating: 5, text: 'I was struggling with my Canada PR application for months. Caspianorthoverseas guided me through every document and I got my PR in record time. Highly recommended!', location: 'Mumbai, India', image: '/testimonials/priya_profile_1772208918133.png', visaPhoto: '/testimonials/priya_canada_pr_1772207964977.png' },
    { name: 'James Wilson', visa: 'Schengen Tourist', rating: 5, text: 'Applied for a Schengen visa for a European trip. The team handled everything from appointment booking to document prep. Stress-free experience!', location: 'London, UK', image: '/testimonials/james_profile_1772208931556.png', visaPhoto: '/testimonials/james_schengen_visa_1772207979268.png' },
    { name: 'Sarah Chen', visa: 'Australia Student', rating: 5, text: 'Got my Australian student visa approved on the first attempt thanks to Caspianorthoverseas. They even helped with university selection and accommodation.', location: 'Beijing, China', image: '/testimonials/sarah_profile_1772208946263.png', visaPhoto: '/testimonials/sarah_australia_visa_1772207995189.png' },
    { name: 'Omar Hassan', visa: 'UK Work Visa', rating: 5, text: 'Professional service from start to finish. My UK work visa was processed quickly and the team was always available to answer my questions.', location: 'Cairo, Egypt', image: '/testimonials/omar_profile_1772208967222.png', visaPhoto: '/testimonials/omar_uk_visa_1772208010422.png' },
    { name: 'Maria Lopez', visa: 'Japan Tourist', rating: 5, text: 'I was worried about the Japan visa requirements but Caspianorthoverseas made it so easy. Documents were perfectly organized and visa came through fast!', location: 'Mexico City, Mexico', image: '/testimonials/maria_profile_1772208981697.png', visaPhoto: '/testimonials/maria_japan_visa_1772208027031.png' },
];

export default function Testimonials() {
    const [current, setCurrent] = useState(0);
    const ref = useRef(null);
    const isInView = useInView(ref, { once: true, margin: '-80px' });
    const isMobile = useIsMobile();
    const show = isMobile || isInView;

    useEffect(() => {
        const timer = setInterval(() => setCurrent(p => (p + 1) % testimonials.length), 5000);
        return () => clearInterval(timer);
    }, []);

    const prev = () => setCurrent(p => (p - 1 + testimonials.length) % testimonials.length);
    const next = () => setCurrent(p => (p + 1) % testimonials.length);

    return (
        <section id="testimonials" className="relative py-24 md:py-32 overflow-hidden" style={{ background: 'var(--t-bg-section)', transition: 'background 0.4s ease' }}>
            {/* Ambient blue background accents */}
            <div className="absolute top-1/4 left-1/4 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px] bg-[var(--t-blob-1)] rounded-full blur-[150px] pointer-events-none" />
            <div className="absolute bottom-[-10%] right-[-10%] w-[600px] h-[600px] bg-[var(--t-blob-2)] rounded-full blur-[150px] pointer-events-none" />

            <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8" ref={ref}>
                <motion.div initial={isMobile ? false : { opacity: 0, y: 30 }} animate={show ? { opacity: 1, y: 0 } : {}} transition={{ duration: 0.6 }} className="text-center mb-16">
                    <span className="inline-block px-4 py-1.5 rounded-full gradient-gold text-navy font-bold text-sm tracking-wider uppercase mb-4">Client Stories</span>
                    <h2 className="text-3xl md:text-5xl font-heading font-bold mb-4">
                        <span className="t-text">What Our Clients </span><span className="text-gradient-gold">Say</span>
                    </h2>
                    <p className="t-text-muted max-w-xl mx-auto text-lg">Real stories from real clients who achieved their visa dreams</p>
                </motion.div>

                <motion.div initial={isMobile ? false : { opacity: 0, y: 40 }} animate={show ? { opacity: 1, y: 0 } : {}} transition={{ duration: 0.6, delay: 0.2 }} className="max-w-3xl mx-auto">
                    <div className="glass-card rounded-3xl p-8 md:p-12 relative">
                        <Quote className="absolute top-6 left-6 w-10 h-10 text-gold/15" />

                        <div className="relative z-10 text-center">
                            {testimonials[current].visaPhoto && (
                                <motion.div
                                    key={current}
                                    initial={{ opacity: 0, scale: 0.95 }}
                                    animate={{ opacity: 1, scale: 1 }}
                                    transition={{ duration: 0.5 }}
                                    className="mb-8 overflow-hidden rounded-2xl shadow-xl relative border border-gold/20 flex justify-center bg-black/10 w-full"
                                >
                                    <img src={testimonials[current].visaPhoto} alt={testimonials[current].visa} className="w-full h-auto max-h-[300px] object-cover object-center" />
                                    <div className="absolute inset-x-0 bottom-0 top-1/2 bg-gradient-to-t from-black/90 to-transparent"></div>
                                    <div className="absolute bottom-4 left-4 right-4 flex flex-col items-center">
                                        <div className="text-xl md:text-2xl font-bold text-white mb-1 uppercase tracking-wider text-center drop-shadow-lg">{testimonials[current].visa}</div>
                                        <div className="text-gold font-bold uppercase text-lg bg-black/40 px-3 py-1 rounded-lg backdrop-blur-sm border border-gold/30">APPROVED!</div>
                                    </div>
                                </motion.div>
                            )}

                            <div className="flex justify-center gap-1 mb-6">
                                {[...Array(testimonials[current].rating)].map((_, i) => (
                                    <Star key={i} className="w-5 h-5 fill-gold text-gold" />
                                ))}
                            </div>

                            <p className="text-lg md:text-xl t-text-sec leading-relaxed mb-8 italic">
                                "{testimonials[current].text}"
                            </p>

                            <div className="flex items-center justify-center gap-4">
                                {testimonials[current].image ? (
                                    <img src={testimonials[current].image} alt={testimonials[current].name} className="w-16 h-16 rounded-full object-cover border-2 border-gold/40 shadow-lg" />
                                ) : (
                                    <div className="w-12 h-12 rounded-full gradient-gold flex items-center justify-center text-navy font-bold text-lg font-heading">
                                        {testimonials[current].name.charAt(0)}
                                    </div>
                                )}
                                <div className="text-left">
                                    <div className="font-heading font-bold t-text">{testimonials[current].name}</div>
                                    <div className="text-sm text-gold">{testimonials[current].visa}</div>
                                    <div className="text-xs t-text-faint">{testimonials[current].location}</div>
                                </div>
                            </div>
                        </div>

                        <div className="flex items-center justify-center gap-4 mt-8">
                            <button onClick={prev} className="w-10 h-10 rounded-full glass-card flex items-center justify-center t-text-muted hover:text-gold hover:border-gold/30 transition-all">
                                <ChevronLeft className="w-5 h-5" />
                            </button>
                            <div className="flex gap-2">
                                {testimonials.map((_, i) => (
                                    <button key={i} onClick={() => setCurrent(i)} className={`w-2 h-2 rounded-full transition-all duration-300 ${i === current ? 'w-6 bg-gold' : 'bg-current/15 hover:bg-current/30'}`} style={{ backgroundColor: i === current ? undefined : 'var(--t-text-faint)' }} />
                                ))}
                            </div>
                            <button onClick={next} className="w-10 h-10 rounded-full glass-card flex items-center justify-center t-text-muted hover:text-gold hover:border-gold/30 transition-all">
                                <ChevronRight className="w-5 h-5" />
                            </button>
                        </div>
                    </div>
                </motion.div>
            </div>
        </section>
    );
}

